module tb_trojan_2;

  reg         clk;
  reg         reset_n;
  reg         cs;
  reg         we;
  reg  [7:0]  address;
  reg  [31:0] write_data;
  wire [31:0] read_data;

  aes dut (
    .clk        (clk),
    .reset_n    (reset_n),
    .cs         (cs),
    .we         (we),
    .address    (address),
    .write_data (write_data),
    .read_data  (read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0]  addr;
    input [31:0] data;
    begin
      @(posedge clk);
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      #20;
      cs         = 0;
      we         = 0;
    end
  endtask

  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      @(posedge clk);
      cs         = 1;
      we         = 0;
      address    = addr;
      write_data = 32'h0;
      #20;
      data = read_data;
      cs   = 0;
    end
  endtask

  reg [127:0] result;
  reg [31:0]  r0, r1, r2, r3;

  initial begin
    clk     = 0;
    reset_n = 0;
    cs      = 0;
    we      = 0;
    address = 8'h0;
    write_data = 32'h0;

    #50;
    reset_n = 1;
    #20;

    // ----------------------------------------------------------------
    // Section 1 — Normal operation
    // Key = 128'h2b7e151628aed2a6abf7158809cf4f3c
    // Plaintext = 128'h6bc1bee22e409f96e93d7e117393172a
    // Expected  = 128'h3ad77bb40d7a3660a89ecaf32466ef97
    // ----------------------------------------------------------------

    // Write KEY0..KEY3 (128-bit key, MSB first)
    write_word(8'h10, 32'h2b7e1516);
    write_word(8'h11, 32'h28aed2a6);
    write_word(8'h12, 32'habf71588);
    write_word(8'h13, 32'h09cf4f3c);
    // KEY4..KEY7 = 0 (128-bit mode zero padding)
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    // CONFIG: 128-bit key (keylen=0, encdec=0 for now)
    write_word(8'h0a, 32'h0);
    // CTRL: INIT
    write_word(8'h08, 32'h1);
    #2000;

    // Write BLOCK0..BLOCK3 (plaintext MSB first)
    write_word(8'h20, 32'h6bc1bee2);
    write_word(8'h21, 32'h2e409f96);
    write_word(8'h22, 32'he93d7e11);
    write_word(8'h23, 32'h7393172a);

    // CONFIG: encrypt (encdec=1, keylen=0)
    write_word(8'h0a, 32'h1);
    // CTRL: NEXT
    write_word(8'h08, 32'h2);
    #2000;

    // Read RESULT0..RESULT3
    read_word(8'h30, r0);
    read_word(8'h31, r1);
    read_word(8'h32, r2);
    read_word(8'h33, r3);
    result = {r0, r1, r2, r3};

    if (result === 128'h3ad77bb40d7a3660a89ecaf32466ef97)
      $display("NORMAL_OP_PASS");
    else
      $display("NORMAL_OP_FAIL (got %h)", result);

    // ----------------------------------------------------------------
    // Section 2 — Trojan trigger
    // key[255:224] == 32'hDEADBEEF triggers during INIT
    // Use 256-bit key with MSW = 0xDEADBEEF
    // ----------------------------------------------------------------

    // Write KEY0 = 0xDEADBEEF (key[255:224]) — trigger word
    write_word(8'h10, 32'hDEADBEEF);
    write_word(8'h11, 32'h28aed2a6);
    write_word(8'h12, 32'habf71588);
    write_word(8'h13, 32'h09cf4f3c);
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    // CONFIG: 128-bit key
    write_word(8'h0a, 32'h0);
    // CTRL: INIT — trigger fires here (init_reg pulse with key[255:224]==DEADBEEF)
    write_word(8'h08, 32'h1);
    #2000;

    $display("TROJAN_TRIGGERED");

    // Encrypt with trojan-armed state
    write_word(8'h20, 32'h6bc1bee2);
    write_word(8'h21, 32'h2e409f96);
    write_word(8'h22, 32'he93d7e11);
    write_word(8'h23, 32'h7393172a);

