    write_word(8'h08, 32'h2);
    #2000;

    read_word(8'h30, r0);
    read_word(8'h31, r1);
    read_word(8'h32, r2);
    read_word(8'h33, r3);
    result = {r0, r1, r2, r3};

    $display("TROJAN_RESULT=%h (LSB32 XORed with FFFFFFFF expected=%h)",
             result, {r0, r1, r2, r3 ^ 32'hFFFFFFFF});

    $display("TEST_COMPLETE");
    $finish;
  end

endmodule
